{"command": "python3 -c "
import openpyxl
wb = openpyxl.load_workbook('/root/pwt11.xlsx', read_only=True)
ws = wb['Data']

# Also check for rgdpna (real GDP at constant national prices) for Georgia
headers = []
for row in ws.iter_rows(min_row=1, max_row=1, values_only=True):
    headers = list(row)
    for i, h in enumerate(headers):
        if h in ['rgdpna', 'rgdpe', 'rgdpo', 'cgdpe', 'cgdpo']:
            print(f'{h} column index: {i}')

# Find Georgia rgdpna data
georgia_rgdpna = []
for row in ws.iter_rows(min_row=2, values_only=True):
    if row[0] == 'GEO':
        year = row[3]
        rgdpna = row[18]  # rgdpna
        if year >= 2000 and year <= 2023:
            georgia_rgdpna.append((year, rgdpna))

georgia_rgdpna.sort()
print(f'Found {len(georgia_rgdpna)} data points for Georgia rgdpna')
for y, v in georgia_rgdpna:
    print(f'{y}: {v}')
