import xml.etree.ElementTree as ET
tree = ET.parse('/root/ecb_cfc.xml')
root = tree.getroot()

# Find all Obs elements
ns = {
    'message': 'http://www.sdmx.org/resources/sdmxml/schemas/v2_1/message',
    'generic': 'http://www.sdmx.org/resources/sdmxml/schemas/v2_1/data/generic',
    'common': 'http://www.sdmx.org/resources/sdmxml/schemas/v2_1/common'
}

# Find Series elements
for series in root.iter():
    if 'Series' in series.tag:
        print('Series found')
        for obs in series.iter():
            if 'Obs' in obs.tag:
                # Get ObsDimension and ObsValue
                dim = None
                val = None
                for child in obs:
                    if 'ObsDimension' in child.tag:
                        dim = child.attrib.get('value', '')
                    if 'ObsValue' in child.tag:
                        val = child.attrib.get('value', '')
                if dim and val:
                    print(f'  {dim}: {val}')
"", "description": "Parse ECB CFC XML data", "timeout": 15000}

